class Solution:
    def countPrimes(self, n):
        # Linear sieve — different implementation from the optimal Eratosthenes sieve
        if n < 2:
            return 0
        is_composite = bytearray(n)
        primes = []
        for i in range(2, n):
            if not is_composite[i]:
                primes.append(i)
            for p in primes:
                if i * p >= n:
                    break
                is_composite[i * p] = 1
                if i % p == 0:
                    break
        return len(primes)

