class Solution:
    def countPrimes(self, n):
        if n < 2:
            return 0
        sieve = [True] * n
        sieve[0] = sieve[1] = False
        p = 2
        while p * p < n:
            if sieve[p]:
                for multiple in range(p * p, n, p):
                    sieve[multiple] = False
            p += 1
        return sum(sieve)

