var countPrimes = function(n) {
    if (n < 2) return 0;
    const sieve = new Uint8Array(n).fill(1);
    sieve[0] = sieve[1] = 0;
    for (let p = 2; p * p < n; p++) {
        if (sieve[p]) {
            for (let m = p * p; m < n; m += p) {
                sieve[m] = 0;
            }
        }
    }
    let count = 0;
    for (let i = 2; i < n; i++) if (sieve[i]) count++;
    return count;
};
